#!/usr/bin/env python3
"""
Verification script to check that the USD files have the required structure.
"""

from pxr import Usd, UsdGeom, UsdLux
import os


def verify_assets_usda(filepath):
    """Verify that assets.usda has the expected structure."""
    print("\n=== Verifying assets.usda ===")
    stage = Usd.Stage.Open(filepath)

    expected_prims = [
        "/Assets",
        "/Assets/Chair",
        "/Assets/Chair/Geo",
        "/Assets/Chair_Xform",
        "/Assets/Chair_Xform/Geo",
    ]

    for prim_path in expected_prims:
        if stage.GetPrimAtPath(prim_path):
            print(f"✓ Found: {prim_path}")
        else:
            print(f"✗ Missing: {prim_path}")
            return False

    if (
        "/Assets/Chair"
        not in stage.GetPrimAtPath("/Assets/Chair").GetVariantSets().GetNames()
    ):
        print("✗ Chair missing variant set 'modelVariant'")
        return False
    else:
        print("✓ Chair has variant set 'modelVariant'")

    vs = stage.GetPrimAtPath("/Assets/Chair").GetVariantSet("modelVariant")
    if "simple" not in vs.GetVariantNames():
        print("✗ Chair missing variant 'simple'")
        return False
    else:
        print("✓ Chair has variant 'simple'")

    if "detailed" not in vs.GetVariantNames():
        print("✗ Chair missing variant 'detailed'")
        return False
    else:
        print("✓ Chair has variant 'detailed'")

    mesh_prim = stage.GetPrimAtPath("/Assets/Chair_Xform/Geo")
    if mesh_prim.IsValid() and mesh_prim.GetTypeName() == "Mesh":
        print("✓ Chair_Xform/Geo is a Mesh")
    else:
        print("✗ Chair_Xform/Geo is not a Mesh")
        return False

    return True


def verify_shot_usda(filepath, assets_path):
    """Verify that shot.usda has the expected structure."""
    print("\n=== Verifying shot.usda ===")
    stage = Usd.Stage.Open(filepath)

    expected_prims = [
        "/Shot",
        "/Shot/Set",
        "/Shot/Set/ChairA",
        "/Shot/Set/ChairB",
        "/Shot/Lighting",
    ]

    for prim_path in expected_prims:
        if stage.GetPrimAtPath(prim_path):
            print(f"✓ Found: {prim_path}")
        else:
            print(f"✗ Missing: {prim_path}")
            return False

    if (
        not stage.GetRootLayer().subLayerPaths
        or assets_path not in stage.GetRootLayer().subLayerPaths
    ):
        print("✗ Missing sublayer to assets.usda")
        return False
    else:
        print(f"✓ Has sublayer: {assets_path}")

    chairA_prim = stage.GetPrimAtPath("/Shot/Set/ChairA")
    if chairA_prim.IsValid():
        xformable = UsdGeom.Xformable(chairA_prim)
        if xformable.GetXformOps():
            print("✓ ChairA has xformOp:translate")
        else:
            print("✗ ChairA missing xformOp:translate")
            return False
    else:
        print("✗ ChairA not found")
        return False

    chairB_prim = stage.GetPrimAtPath("/Shot/Set/ChairB")
    if chairB_prim.IsValid():
        xformable = UsdGeom.Xformable(chairB_prim)
        if xformable.GetXformOps():
            print("✓ ChairB has xformOp:translate")
        else:
            print("✗ ChairB missing xformOp:translate")
            return False
    else:
        print("✗ ChairB not found")
        return False

    lighting_prim = stage.GetPrimAtPath("/Shot/Lighting")
    if lighting_prim.IsValid():
        if "lightingVariant" not in lighting_prim.GetVariantSets().GetNames():
            print("✗ Lighting missing variant set 'lightingVariant'")
            return False
        else:
            print("✓ Lighting has variant set 'lightingVariant'")
    else:
        print("✗ Lighting not found")
        return False

    variant_set = lighting_prim.GetVariantSet("lightingVariant")
    if "day" not in variant_set.GetVariantNames():
        print("✗ Lighting missing variant 'day'")
        return False
    else:
        print("✓ Lighting has variant 'day'")

    if "night" not in variant_set.GetVariantNames():
        print("✗ Lighting missing variant 'night'")
        return False
    else:
        print("✓ Lighting has variant 'night'")

    day_light = stage.GetPrimAtPath("/Shot/Lighting/Sun")
    if day_light.IsValid() and day_light.GetTypeName() == "DistantLight":
        intensity_attr = UsdLux.DistantLight(day_light).GetIntensityAttr()
        if intensity_attr:
            print(f"✓ Sun light exists with intensity={intensity_attr.Get()}")
        else:
            print("✗ Sun light missing intensity")
            return False
    else:
        print("✗ Sun light not found or not DistantLight")
        return False

    night_light = stage.GetPrimAtPath("/Shot/Lighting/Sky")
    if night_light.IsValid() and night_light.GetTypeName() == "DomeLight":
        intensity_attr = UsdLux.DomeLight(night_light).GetIntensityAttr()
        if intensity_attr:
            print(f"✓ Sky light exists with intensity={intensity_attr.Get()}")
        else:
            print("✗ Sky light missing intensity")
            return False
    else:
        print("✗ Sky light not found or not DomeLight")
        return False

    return True


def main():
    script_dir = os.path.dirname(os.path.abspath(__file__))
    assets_path = os.path.join(script_dir, "assets.usda")
    shot_path = os.path.join(script_dir, "shot.usda")

    if not os.path.exists(assets_path):
        print(f"✗ assets.usda not found at {assets_path}")
        return False

    if not os.path.exists(shot_path):
        print(f"✗ shot.usda not found at {shot_path}")
        return False

    assets_ok = verify_assets_usda(assets_path)
    shot_ok = verify_shot_usda(shot_path, assets_path)

    if assets_ok and shot_ok:
        print("\n✓✓✓ All verifications passed! ✓✓✓")
        return True
    else:
        print("\n✗✗✗ Some verifications failed! ✗✗✗")
        return False


if __name__ == "__main__":
    success = main()
    exit(0 if success else 1)
